var e=[{id:`L2_1`,type:`dialog`,speaker:`INTERN_FENRIR_NEXT_NULL`,text:{KOREA:`만남이 있으면, 헤어짐이 있듯이. 언젠가는 끝이 올지도 모르겠죠.`,JPN:`出会いがあれば、お別れがあるように。いつかは最後を迎えるかもしれません。`,ENG:`As with every meeting, there comes a farewell. Someday, this might end too.`,TWN:`有相遇就有離別。總有一天會迎來終結吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`INTERN_FENRIR_NEXT_NULL`,text:{KOREA:`하지만 괜찮아요. 그 덕분에 제가 정말로 원하는 게 무엇인지 알게 되었으니까요.`,JPN:`でも大丈夫です。そのおかげで私が本当に望むものが何なのか、わかったんですから。`,ENG:`But it's okay. Because of it, I finally know what matters most to me.`,TWN:`但是沒關係。因為這樣我才知道自己真正想要的是什麼。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NEXT_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`INTERN_FENRIR_NEXT_NULL`,text:{KOREA:`저는 미나 선배를… 그리고 세상을 지킬 거예요. 그게 제 진심입니다……!`,JPN:`私はミナ先輩を……そして世界を守ります。それが私の本気です……！`,ENG:`I want to protect Mina... and this world. That's how I really feel.`,TWN:`我會保護米娜前輩……還有這個世界。這是我的真心話……！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};